List<ArcanoMenor> filtrarPorPalo(String palo) {
  return allArcanosMenores.where((a) => a.palo.toLowerCase() == palo.toLowerCase()).toList();
}

ArcanoMenor? getArcanoMenorPorId(int id) {
  for (var a in allArcanosMenores) { if (a.id == id) return a; }
  return null;
}
